import{c as a,Q as s,j as i,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Browse the library","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/browse-library.md","filePath":"user-guide/browse-library.md","lastUpdated":null}'),r={name:"user-guide/browse-library.md"};function l(h,e,o,d,n,p){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="browse-the-library" tabindex="-1">Browse the library <a class="header-anchor" href="#browse-the-library" aria-label="Permalink to &quot;Browse the library&quot;">​</a></h1><p>Audience: UI users<br> Goal: find, preview, and inspect tracks<br> Type: how-to</p><p>The library panel shows lightweight paginated track rows. Full metadata loads only when you open a track dialog.</p><h2 id="select-the-database" tabindex="-1">Select the database <a class="header-anchor" href="#select-the-database" aria-label="Permalink to &quot;Select the database&quot;">​</a></h2><p>Start the server with a database:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim serve </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">host </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">127.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">port </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8765</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span></code></pre></div><p>Or use the database picker in the UI. The top bar shows summary counters for tracks and analysis coverage.</p><h2 id="search-and-filter" tabindex="-1">Search and filter <a class="header-anchor" href="#search-and-filter" aria-label="Permalink to &quot;Search and filter&quot;">​</a></h2><p>The library search field uses text such as artist, title, genre, or path. The search mode toggle supports:</p><ul><li><code>LIKE</code>: simple broad matching;</li><li><code>FTS</code>: full-text search through the SQLite search index.</li></ul><p>You can also show liked tracks only, filter for the MAEST syncopated-rhythm flag, and reverse the current page order.</p><h2 id="work-with-rows" tabindex="-1">Work with rows <a class="header-anchor" href="#work-with-rows" aria-label="Permalink to &quot;Work with rows&quot;">​</a></h2><p>Track rows expose compact actions:</p><ul><li>preview or pause audio;</li><li>open the metadata dialog;</li><li>like or unlike a track;</li><li>mark a track as a seed;</li><li>add or remove a track from the current set.</li></ul><p>The metadata dialog keeps sources separate: Mutagen file tags, SONARA features, classifier scores, and MAEST genre labels are shown as different blocks. This helps you spot disagreement instead of hiding it.</p><h2 id="refresh-tags" tabindex="-1">Refresh tags <a class="header-anchor" href="#refresh-tags" aria-label="Permalink to &quot;Refresh tags&quot;">​</a></h2><p><code>RefreshTags</code> rereads file tags for already discovered tracks. It updates SQLite metadata. It does not rewrite audio, and it does not remove SONARA, MAEST, MERT, CLAP, or classifier analysis state.</p>',17)])])}const u=a(r,[["render",l]]);export{k as __pageData,u as default};
